<body>
  <div class="container">
    <div class="header">
      <h1>🎯 Customize Your Daily Summary</h1>
      <p>Choose how you want to receive your email summaries</p>
    </div>

    <div class="content">
      <div class="welcome">
        <h2>Welcome,{{ $json.userName }} ! 👋</h2>
        <p>Let's personalize your experience. Select your preferred summary format below.</p>
      </div>

      <div id="errorMessage" class="error-message"></div>

      <form id="preferencesForm">
        <div class="options">
          <!-- Option 1: Action-First Format -->
          <div class="option-card" data-preference="action_first" onclick="selectOption(this)">
            <input type="radio" name="summary_type" value="action_first" id="action_first">
            <div class="option-header">
              <div class="radio-custom"></div>
              <div class="option-title">Action-First Summary</div>
              <span class="badge">Recommended</span>
            </div>
            <div class="option-description">
              Get all your action items at the top, organized by priority. Perfect for starting your day with clear next steps.
            </div>
            <div class="preview">
              <div class="preview-title">📋 Preview Format</div>
              <div class="preview-content">
                <strong style="color: #2C5F5F; display: block; margin-bottom: 8px;">Action Items (3):</strong>
                <div class="preview-item">Evaluate Phillips Precision's CNC services <span style="font-size:12px;color:#999;">(from: The Bridge to Quantum)</span></div>
                <div class="preview-item">Review Q4 budget proposal <span style="font-size:12px;color:#999;">(from: Finance Team)</span></div>
                <div class="preview-item">Approve design mockups <span style="font-size:12px;color:#999;">(from: Sarah Johnson)</span></div>
                <strong style="color: #2C5F5F; display: block; margin: 15px 0 8px;">All Emails (5):</strong>
                <div class="preview-item">The Bridge to Quantum - Request (MEDIUM)</div>
                <div class="preview-item">Q4 Budget Review - Action Required (HIGH)</div>
              </div>
            </div>
          </div>

          <!-- Option 2: Standard Format -->
          <div class="option-card" data-preference="standard" onclick="selectOption(this)">
            <input type="radio" name="summary_type" value="standard" id="standard">
            <div class="option-header">
              <div class="radio-custom"></div>
              <div class="option-title">Standard Summary</div>
            </div>
            <div class="option-description">
              View all emails with their summaries and inline action items. Great for a comprehensive overview.
            </div>
            <div class="preview">
              <div class="preview-title">📧 Preview Format</div>
              <div class="preview-content">
                <strong style="color: #2C5F5F; display: block; margin-bottom: 8px;">The Bridge to Quantum <span style="background:#ffc107;color:#000;padding:2px 8px;border-radius:4px;font-size:11px;margin-left:8px;">MEDIUM</span></strong>
                <div style="font-size:13px;color:#666;margin-bottom:8px;">From: Jonathan | Type: Request | Read Time: 30 seconds</div>
                <div style="margin-bottom:8px;">Phillips Precision follows up to explore CNC machining services...</div>
                <div style="background:#fff3cd;padding:10px;border-radius:6px;font-size:13px;">
                  <strong>📋 Action Items (2):</strong><br>
                  • Evaluate if services fit current needs<br>
                  • Forward to appropriate person if not right contact
                </div>
              </div>
            </div>
          </div>
        </div>

        <div class="action-section">
          <button type="submit" class="btn" id="submitBtn">
            Save Preferences & Continue
          </button>
        </div>
      </form>
    </div>
  </div>

  <div class="success-overlay" id="successOverlay">
    <div class="success-content">
      <div style="font-size: 64px;">✅</div>
      <h2>All Set!</h2>
      <p style="color: #666; margin-bottom: 20px;">Your preferences have been saved successfully.</p>
      <p style="font-size: 14px; color: #999;">
        Redirecting<span class="loading-dots"><span>.</span><span>.</span><span>.</span></span>
      </p>
    </div>
  </div>

  <script>
    const userData = {
  userId: '{{ $json.userId }}',
  userEmail: '{{ $json.userEmail }}',
  userName: '{{ $json.userName }}'
};

    console.log('User data loaded:', userData);

    // Function to select an option
    function selectOption(card) {
      // Remove selected class from all cards
      document.querySelectorAll('.option-card').forEach(c => {
        c.classList.remove('selected');
      });

      // Add selected class to clicked card
      card.classList.add('selected');

      // Check the radio button
      const radio = card.querySelector('input[type="radio"]');
      radio.checked = true;

      console.log('Selected preference:', radio.value);
    }

    // Handle form submission
    document.getElementById('preferencesForm').addEventListener('submit', async function(e) {
      e.preventDefault();

      const selectedPreference = document.querySelector('input[name="summary_type"]:checked');

      if (!selectedPreference) {
        showError('Please select a summary format');
        return;
      }

      const submitBtn = document.getElementById('submitBtn');
      const originalText = submitBtn.textContent;
      submitBtn.innerHTML = 'Saving<span class="loading-dots"><span>.</span><span>.</span><span>.</span></span>';
      submitBtn.disabled = true;

      console.log('Submitting preference:', selectedPreference.value);

      try {
        const baseUrl = window.location.origin;
        const saveUrl = `${baseUrl}/webhook/save-preferences`;

        console.log('Posting to:', saveUrl);

        const response = await fetch(saveUrl, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            userId: userData.userId,
            userEmail: userData.userEmail,
            userName: userData.userName,  // ✅ Include userName
            summaryPreference: selectedPreference.value
          })
        });

        console.log('Response status:', response.status);

        if (!response.ok) {
          const errorText = await response.text();
          console.error('Error response:', errorText);
          throw new Error('Failed to save preferences: ' + response.status);
        }

        // ✅ CHANGED: Display HTML response instead of parsing JSON
        const successHtml = await response.text();
        document.open();
        document.write(successHtml);
        document.close();

      } catch (error) {
        console.error('Error saving preferences:', error);
        showError('Failed to save preferences. Please try again. Error: ' + error.message);
        submitBtn.textContent = originalText;
        submitBtn.disabled = false;
      }
    });

    function showError(message) {
      const errorDiv = document.getElementById('errorMessage');
      errorDiv.textContent = message;
      errorDiv.style.display = 'block';

      // Scroll to error
      errorDiv.scrollIntoView({ behavior: 'smooth', block: 'nearest' });

      setTimeout(() => {
        errorDiv.style.display = 'none';
      }, 5000);
    }

    // Prevent accidental form submission on Enter key
    document.addEventListener('keypress', function(e) {
      if (e.key === 'Enter' && e.target.tagName !== 'BUTTON') {
        e.preventDefault();
      }
    });
  </script>
</body>
</html>
